namespace sv_d13058542e644c7489dc8190f0b92a36.Services;

public class AppointmentService
{
    private static readonly List<string> Doctors =
    [
        "Dr. Smith",
        "Dr. Johnson",
        "Dr. Patel",
        "Dr. Williams"
    ];

    // Doctors that do not accept self-pay
    private static readonly HashSet<string> NoSelfPayDoctors = ["Dr. Smith"];

    // Emails with an outstanding balance
    private static readonly HashSet<string> OutstandingBalanceEmails =
        new(StringComparer.OrdinalIgnoreCase) { "taken@example.com" };

    // Time slots considered already taken (race-condition simulation)
    private static readonly HashSet<string> TakenSlots = ["10:00 AM"];

    public Task<List<string>> GetDoctorsAsync()
    {
        return Task.FromResult(new List<string>(Doctors));
    }

    public Task<List<string>> GetAvailableTimeSlotsAsync(string doctor, DateOnly date)
    {
        // Return a fixed set of slots for any valid doctor + future date
        var slots = new List<string>
        {
            "9:00 AM",
            "10:00 AM",
            "11:00 AM",
            "1:00 PM",
            "2:00 PM",
            "3:00 PM"
        };
        return Task.FromResult(slots);
    }

    /// <summary>
    /// Validates server-side business rules. Returns a dictionary of
    /// field-name → error-message for any violations found.
    /// An empty dictionary means validation passed.
    /// </summary>
    public Task<Dictionary<string, string>> ValidatePatientAsync(
        string email,
        string insuranceProvider,
        string doctor,
        string timeSlot)
    {
        var errors = new Dictionary<string, string>();

        if (OutstandingBalanceEmails.Contains(email))
        {
            errors[nameof(BookingModel.Email)] = "Account has outstanding balance";
        }

        if (insuranceProvider == "None" && NoSelfPayDoctors.Contains(doctor))
        {
            errors[nameof(BookingModel.PreferredDoctor)] =
                "Selected doctor does not accept self-pay patients";
        }

        if (TakenSlots.Contains(timeSlot))
        {
            errors[nameof(BookingModel.TimeSlot)] = "This slot is no longer available";
        }

        return Task.FromResult(errors);
    }
}

using System.ComponentModel.DataAnnotations;

namespace sv_d13058542e644c7489dc8190f0b92a36.Services;

public class BookingModel
{
    // Step 1
    [Required(ErrorMessage = "Patient name is required.")]
    public string PatientName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Email is required.")]
    [EmailAddress(ErrorMessage = "Invalid email format.")]
    public string Email { get; set; } = string.Empty;

    [Required(ErrorMessage = "Phone is required.")]
    public string Phone { get; set; } = string.Empty;

    [Required(ErrorMessage = "Insurance provider is required.")]
    public string InsuranceProvider { get; set; } = string.Empty;

    // Step 2
    [Required(ErrorMessage = "Please select a doctor.")]
    public string PreferredDoctor { get; set; } = string.Empty;

    [Required(ErrorMessage = "Date is required.")]
    [FutureDate(ErrorMessage = "Date must be in the future.")]
    public DateOnly? AppointmentDate { get; set; }

    [Required(ErrorMessage = "Please select a time slot.")]
    public string TimeSlot { get; set; } = string.Empty;

    [Required(ErrorMessage = "Reason for visit is required.")]
    [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer.")]
    public string ReasonForVisit { get; set; } = string.Empty;
}

public class FutureDateAttribute : ValidationAttribute
{
    protected override ValidationResult? IsValid(object? value, ValidationContext validationContext)
    {
        if (value is DateOnly date && date <= DateOnly.FromDateTime(DateTime.Today))
        {
            return new ValidationResult(ErrorMessage);
        }
        return ValidationResult.Success;
    }
}

@page "/book-appointment"
@rendermode InteractiveServer
@using sv_d13058542e644c7489dc8190f0b92a36.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h3>Book a Medical Appointment</h3>

<EditForm Model="Model" OnValidSubmit="HandleSubmit">
    <DataAnnotationsValidator />

    @* ───── STEP 1 ───── *@
    <fieldset>
        <legend>Step 1 – Patient Information</legend>

        <div class="mb-3">
            <label class="form-label">Patient Name</label>
            <InputText class="form-control" @bind-Value="Model.PatientName" />
            <ValidationMessage For="() => Model.PatientName" />
        </div>

        <div class="mb-3">
            <label class="form-label">Email</label>
            <InputText class="form-control" @bind-Value="Model.Email" />
            <ValidationMessage For="() => Model.Email" />
        </div>

        <div class="mb-3">
            <label class="form-label">Phone</label>
            <InputText class="form-control" @bind-Value="Model.Phone" />
            <ValidationMessage For="() => Model.Phone" />
        </div>

        <div class="mb-3">
            <label class="form-label">Insurance Provider</label>
            <InputSelect class="form-select" @bind-Value="Model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="() => Model.InsuranceProvider" />
        </div>

        @if (!ShowStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">
                Next
            </button>
        }
    </fieldset>

    @* ───── STEP 2 ───── *@
    @if (ShowStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2 – Appointment Details</legend>

            <div class="mb-3">
                <label class="form-label">Preferred Doctor</label>
                <InputSelect class="form-select" @bind-Value="Model.PreferredDoctor"
                             @bind-Value:after="OnDoctorChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in Doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.PreferredDoctor" />
            </div>

            <div class="mb-3">
                <label class="form-label">Date</label>
                <InputDate class="form-control" @bind-Value="Model.AppointmentDate"
                           @bind-Value:after="OnDateChanged" />
                <ValidationMessage For="() => Model.AppointmentDate" />
            </div>

            <div class="mb-3">
                <label class="form-label">Time Slot</label>
                <InputSelect class="form-select" @bind-Value="Model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in TimeSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.TimeSlot" />
            </div>

            <div class="mb-3">
                <label class="form-label">Reason for Visit</label>
                <InputTextArea class="form-control" @bind-Value="Model.ReasonForVisit" rows="3" />
                <ValidationMessage For="() => Model.ReasonForVisit" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="BackToStep1">
                Back
            </button>
            <button type="button" class="btn btn-info me-2" @onclick="CheckAvailability">
                Check Availability
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!AvailabilityConfirmed)">
                Book Appointment
            </button>
        </fieldset>
    }

    @if (IsSubmitted)
    {
        <div class="alert alert-success mt-3">Appointment booked successfully!</div>
    }
</EditForm>

@code {
    private BookingModel Model { get; set; } = new();
    private List<string> Doctors { get; set; } = [];
    private List<string> TimeSlots { get; set; } = [];
    private bool ShowStep2 { get; set; }
    private bool AvailabilityConfirmed { get; set; }
    private bool IsSubmitted { get; set; }

    private EditContext? editContext;
    private ValidationMessageStore? messageStore;

    protected override async Task OnInitializedAsync()
    {
        Doctors = await AppointmentSvc.GetDoctorsAsync();
        editContext = new EditContext(Model);
        messageStore = new ValidationMessageStore(editContext);
    }

    private void ProceedToStep2()
    {
        editContext ??= new EditContext(Model);
        messageStore?.Clear();

        // Validate only step-1 fields
        var step1Valid =
            !string.IsNullOrWhiteSpace(Model.PatientName) &&
            !string.IsNullOrWhiteSpace(Model.Email) &&
            new System.ComponentModel.DataAnnotations.EmailAddressAttribute().IsValid(Model.Email) &&
            !string.IsNullOrWhiteSpace(Model.Phone) &&
            !string.IsNullOrWhiteSpace(Model.InsuranceProvider);

        if (!step1Valid)
        {
            // Trigger full validation so DataAnnotationsValidator shows messages
            editContext.Validate();
            return;
        }

        ShowStep2 = true;
        AvailabilityConfirmed = false;
    }

    private async Task OnDoctorChanged()
    {
        AvailabilityConfirmed = false;
        await LoadTimeSlots();
    }

    private async Task OnDateChanged()
    {
        AvailabilityConfirmed = false;
        await LoadTimeSlots();
    }

    private async Task LoadTimeSlots()
    {
        if (!string.IsNullOrEmpty(Model.PreferredDoctor) && Model.AppointmentDate.HasValue)
        {
            TimeSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                Model.PreferredDoctor, Model.AppointmentDate.Value);
        }
        else
        {
            TimeSlots = [];
        }
        Model.TimeSlot = string.Empty;
    }

    private async Task CheckAvailability()
    {
        editContext ??= new EditContext(Model);
        messageStore?.Clear();
        editContext.NotifyValidationStateChanged();

        // Run data-annotation validation first
        var isValid = editContext.Validate();
        if (!isValid) return;

        // Server-side business rules
        var errors = await AppointmentSvc.ValidatePatientAsync(
            Model.Email,
            Model.InsuranceProvider,
            Model.PreferredDoctor,
            Model.TimeSlot);

        if (errors.Count > 0)
        {
            foreach (var (field, message) in errors)
            {
                var fieldId = editContext.Field(field);
                messageStore!.Add(fieldId, message);
            }
            editContext.NotifyValidationStateChanged();
            AvailabilityConfirmed = false;
            return;
        }

        AvailabilityConfirmed = true;
    }

    private void BackToStep1()
    {
        ShowStep2 = false;
        AvailabilityConfirmed = false;
        messageStore?.Clear();
        editContext?.NotifyValidationStateChanged();
    }

    private void HandleSubmit()
    {
        if (!AvailabilityConfirmed) return;
        IsSubmitted = true;
    }
}

